CREATE OR REPLACE FUNCTION restaurant.check_pivot_tenant_coherence_commandes()
RETURNS TRIGGER AS $$
DECLARE
    client_hotel      BIGINT;
    reservation_hotel BIGINT;
    facture_hotel     BIGINT;
BEGIN
    IF NEW.client_id IS NOT NULL THEN
        SELECT hotel_id INTO client_hotel FROM client.clients
            WHERE client_id = NEW.client_id;
        IF NEW.hotel_id IS DISTINCT FROM client_hotel THEN
            RAISE EXCEPTION 'Cross-tenant commande rejected: commande.hotel_id=% client.hotel_id=%',
                NEW.hotel_id, client_hotel;
        END IF;
    END IF;

    IF NEW.reservation_id IS NOT NULL THEN
        SELECT hotel_id INTO reservation_hotel FROM hebergement.reservations
            WHERE reservation_id = NEW.reservation_id;
        IF NEW.hotel_id IS DISTINCT FROM reservation_hotel THEN
            RAISE EXCEPTION 'Cross-tenant commande rejected: commande.hotel_id=% reservation.hotel_id=%',
                NEW.hotel_id, reservation_hotel;
        END IF;
    END IF;

    IF NEW.facture_id IS NOT NULL THEN
        SELECT hotel_id INTO facture_hotel FROM finance.factures
            WHERE facture_id = NEW.facture_id;
        IF NEW.hotel_id IS DISTINCT FROM facture_hotel THEN
            RAISE EXCEPTION 'Cross-tenant commande rejected: commande.hotel_id=% facture.hotel_id=%',
                NEW.hotel_id, facture_hotel;
        END IF;
    END IF;

    RETURN NEW;
END;
$$ LANGUAGE plpgsql

CREATE OR REPLACE FUNCTION restaurant.check_pivot_tenant_coherence_lignes_commande()
RETURNS TRIGGER AS $$
DECLARE
    commande_hotel BIGINT;
    article_hotel  BIGINT;
BEGIN
    SELECT hotel_id INTO commande_hotel FROM restaurant.commandes
        WHERE commande_id = NEW.commande_id;
    IF commande_hotel IS NULL THEN
        RAISE EXCEPTION 'Cross-tenant ligne_commande rejected: commande_id=% not found',
            NEW.commande_id;
    END IF;
    IF NEW.hotel_id IS DISTINCT FROM commande_hotel THEN
        RAISE EXCEPTION 'Cross-tenant ligne_commande rejected: ligne.hotel_id=% commande.hotel_id=%',
            NEW.hotel_id, commande_hotel;
    END IF;

    SELECT hotel_id INTO article_hotel FROM restaurant.articles_menus
        WHERE article_id = NEW.article_id;
    IF article_hotel IS NULL THEN
        RAISE EXCEPTION 'Cross-tenant ligne_commande rejected: article_id=% not found',
            NEW.article_id;
    END IF;
    IF NEW.hotel_id IS DISTINCT FROM article_hotel THEN
        RAISE EXCEPTION 'Cross-tenant ligne_commande rejected: ligne.hotel_id=% article.hotel_id=%',
            NEW.hotel_id, article_hotel;
    END IF;

    RETURN NEW;
END;
$$ LANGUAGE plpgsql

CREATE OR REPLACE FUNCTION restaurant.check_pivot_tenant_coherence_tickets()
RETURNS TRIGGER AS $$
DECLARE
    commande_hotel BIGINT;
BEGIN
    SELECT hotel_id INTO commande_hotel FROM restaurant.commandes
        WHERE commande_id = NEW.commande_id;
    IF commande_hotel IS NULL THEN
        RAISE EXCEPTION 'Cross-tenant ticket rejected: commande_id=% not found',
            NEW.commande_id;
    END IF;
    IF NEW.hotel_id IS DISTINCT FROM commande_hotel THEN
        RAISE EXCEPTION 'Cross-tenant ticket rejected: ticket.hotel_id=% commande.hotel_id=%',
            NEW.hotel_id, commande_hotel;
    END IF;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql

CREATE OR REPLACE FUNCTION restaurant.check_pivot_tenant_coherence_recettes_articles()
RETURNS TRIGGER AS $$
DECLARE
    article_hotel BIGINT;
    produit_hotel BIGINT;
BEGIN
    SELECT hotel_id INTO article_hotel FROM restaurant.articles_menus
        WHERE article_id = NEW.article_id;
    IF article_hotel IS NULL THEN
        RAISE EXCEPTION 'Cross-tenant recette rejected: article_id=% not found',
            NEW.article_id;
    END IF;
    IF NEW.hotel_id IS DISTINCT FROM article_hotel THEN
        RAISE EXCEPTION 'Cross-tenant recette rejected: recette.hotel_id=% article.hotel_id=%',
            NEW.hotel_id, article_hotel;
    END IF;

    SELECT hotel_id INTO produit_hotel FROM inventory.produits
        WHERE produit_id = NEW.produit_id;
    IF produit_hotel IS NULL THEN
        RAISE EXCEPTION 'Cross-tenant recette rejected: produit_id=% not found',
            NEW.produit_id;
    END IF;
    IF NEW.hotel_id IS DISTINCT FROM produit_hotel THEN
        RAISE EXCEPTION 'Cross-tenant recette rejected: recette.hotel_id=% produit.hotel_id=%',
            NEW.hotel_id, produit_hotel;
    END IF;

    RETURN NEW;
END;
$$ LANGUAGE plpgsql
